+            for _ in 0..10 {
+                tuner.tick(&high_memory_metrics());
+            }
+
+            tuner.params().clone()
+        });
+    });
+
+    group.finish();
+}
+
+fn bench_config() -> Criterion {
+    bench_common::emit_bench_artifacts("auto_tuning", BUDGETS);
+    Criterion::default().configure_from_args()
+}
+
+criterion_group!(
+    name = benches;
+    config = bench_config();
+    targets = bench_parameter_tick,
