+
+    // Record some activity to make snapshot non-trivial
+    for i in 0..10 {
+        scheduler.record_capture(i, 1024);
+    }
+
+    group.bench_function("snapshot_with_activity", |b| {
+        b.iter(|| scheduler.snapshot());
+    });
