+
+fn bench_scheduler_update_budget(c: &mut Criterion) {
+    let mut group = c.benchmark_group("scheduler_update_budget");
+
+    let mut scheduler = CaptureScheduler::new(CaptureBudgetConfig {
+        max_captures_per_sec: 50,
