+        } else {
+            Some(now.saturating_sub(i64::try_from(i).unwrap_or(0) * 50))
+        };
+
+        accounts.push(AccountRecord {
+            id: i64::try_from(i).unwrap_or(0),
+            account_id: format!("acct-{i:03}"),
