+            tokens_used: Some(10_000 + i64::try_from(i).unwrap_or(0)),
+            tokens_remaining: Some(5_000 - i64::try_from(i % 500).unwrap_or(0)),
+            tokens_limit: Some(15_000),
+            last_refreshed_at: now,
+            last_used_at,
+            created_at: now,
