+                        (tmp, index, new_docs)
+                    },
+                    |(_tmp, mut index, new_docs)| {
+                        let _ = index.ingest_documents(
+                            black_box(&new_docs),
+                            black_box(99999),
+                            false,
+                            None,
+                        );
+                    },
+                );
+            },
+        );
+    }
+
+    group.finish();
+}
+
+// ---------------------------------------------------------------------------
