+    bench_native_backpressure_impact(c);
+    bench_legacy_process_spawn_baseline(c);
+    bench_common::emit_bench_artifacts("native_events_latency", BUDGETS);
+}
+
+criterion_group!(benches, bench_suite);
+criterion_main!(benches);

