+    });
+    group.finish();
+}
+
+fn bench_importance_budget_enforcement(c: &mut Criterion) {
+    let mut group = c.benchmark_group("scrollback_eviction/importance_byte_budget_enforcement");
+    let seed = synthesize_scored_lines(10_000);
