+
+// =============================================================================
+// Template extraction benchmarks
+// =============================================================================
+
+fn bench_template_extraction(c: &mut Criterion) {
+    let mut group = c.benchmark_group("semantic_template_extraction");
+
+    for group_size in [10, 50, 100] {
+        let lines: Vec<String> = (1..=group_size)
