+/// Calculate average content size.
+fn avg_content_size() -> f64 {
+    let total: usize = (0..1000).map(|i| generate_content(0, i).len()).sum();
+    #[allow(clippy::cast_precision_loss)]
+    let result = total as f64 / 1000.0;
+    result
+}
