+        group.bench_with_input(
+            BenchmarkId::new("size_per_segment", label),
+            &(num_panes, segs_per_pane),
+            |b, &(panes, segs)| {
+                b.to_async(&rt).iter(|| async {
+                    let (_dir, db_path) = temp_db();
