+fn generate_panes(count: usize) -> Vec<PaneInfo> {
+    let mut panes = Vec::with_capacity(count);
+    for i in 0..count {
+        panes.push(PaneInfo {
+            window_id: 0,
+            tab_id: (i / 4) as u64,
+            pane_id: i as u64,
+            domain_id: None,
+            domain_name: None,
+            workspace: Some("default".to_string()),
+            size: Some(PaneSize {
+                rows: 24,
+                cols: 80,
+                pixel_width: Some(640),
+                pixel_height: Some(384),
+                dpi: None,
+            }),
+            rows: None,
+            cols: None,
+            title: Some(format!("pane-{i}")),
+            cwd: Some(format!("file:///home/user/project-{i}")),
+            tty_name: None,
+            cursor_x: Some(0),
+            cursor_y: Some(0),
+            cursor_visibility: None,
+            left_col: None,
+            top_row: None,
+            is_active: i == 0,
+            is_zoomed: false,
+            extra: HashMap::new(),
+        });
+    }
+    panes
+}
